# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import functions_framework
from google.cloud import storage, firestore, pubsub_v1
import os
import json

# Initialize Google Cloud clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

# Configuration (replace with your actual project ID and topic name)
PROJECT_ID = os.environ.get('GCP_PROJECT', 'your-gcp-project-id')
PUBSUB_TOPIC_NAME = 'your-pubsub-topic-name' # e.g., 'file-processed-events'
PUBSUB_TOPIC_PATH = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC_NAME)

@functions_framework.cloud_event
def process_gcs_file(cloud_event):
    """
    Processes a file uploaded to Google Cloud Storage.
    - Reads content from the GCS file.
    - Writes metadata and partial content to Firestore.
    - Publishes a message to Pub/Sub with processing details.
    """
    data = cloud_event.data
    event_id = cloud_event["id"]
    event_timestamp = cloud_event["time"]

    bucket_name = data["bucket"]
    file_name = data["name"]
    file_generation = data["generation"]
    content_type = data.get("contentType", "application/octet-stream")
    file_size = data.get("size", 0)

    print(f"Event ID: {event_id}")
    print(f"Timestamp: {event_timestamp}")
    print(f"Processing file: gs://{bucket_name}/{file_name} (generation: {file_generation}, type: {content_type}, size: {file_size} bytes)")

    try:
        # 1. Read content from GCS
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Download a small portion of the file content for demonstration
        # In a real scenario, you might parse CSV, JSON, images, etc.
        # For large files, consider using blob.download_as_text() or stream processing.
        file_content_sample = ""
        try:
            # Attempt to read as text if it seems like a text file
            if content_type.startswith('text/') or 'json' in content_type or 'xml' in content_type:
                file_content_sample = blob.download_as_text(max_bytes=1024) # Read up to 1KB
            else:
                # For binary files, just note it or read specific metadata
                file_content_sample = f"Binary file (type: {content_type}). Not displaying content sample."
        except Exception as e:
            file_content_sample = f"Could not read file content (error: {e}). It might be binary or too large."

        print(f"File content sample: {file_content_sample[:200]}...") # Print first 200 chars

        # 2. Write to Firestore
        doc_ref = firestore_client.collection('processed_files').document(f"{bucket_name}_{file_name.replace('/', '_')}_{file_generation}")
        firestore_data = {
            "bucket": bucket_name,
            "fileName": file_name,
            "fileGeneration": file_generation,
            "contentType": content_type,
            "fileSize": int(file_size),
            "processingTimestamp": firestore.SERVER_TIMESTAMP,
            "eventTimestamp": event_timestamp,
            "contentSample": file_content_sample[:500] # Store up to 500 chars of sample
        }
        doc_ref.set(firestore_data)
        print(f"Successfully wrote file metadata to Firestore document: {doc_ref.id}")

        # 3. Publish to Pub/Sub
        pubsub_message_data = {
            "bucket": bucket_name,
            "fileName": file_name,
            "fileGeneration": file_generation,
            "contentType": content_type,
            "fileSize": int(file_size),
            "firestoreDocId": doc_ref.id,
            "processedByFunction": "process_gcs_file",
            "correlationId": event_id
        }
        
        # Pub/Sub message data must be bytes
        future = publisher.publish(
            PUBSUB_TOPIC_PATH,
            json.dumps(pubsub_message_data).encode('utf-8'),
            origin="gcs_event_processor",
            file_name=file_name
        )
        message_id = future.result()
        print(f"Published message to Pub/Sub topic {PUBSUB_TOPIC_NAME} with ID: {message_id}")

    except Exception as e:
        print(f"Error processing file gs://{bucket_name}/{file_name}: {e}")
        # Depending on your error handling strategy, you might re-raise the exception
        # to trigger a retry, or log it and continue.
        raise # Re-raise for Cloud Functions to potentially retry